diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
index bcc6e56059270..e7ab17f82d7be 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
@@ -3649,11 +3649,6 @@ bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
     return true;
   }

-  if (const CallBase *CB = dyn_cast<CallBase>(VInst)) {
-    FPClassTest NoFPClass = CB->getParamNoFPClass(U.getOperandNo());
-    DemandedMask &= ~NoFPClass;
-  }
-
   if (Depth == MaxAnalysisRecursionDepth) {
     Known.knownNot(~DemandedMask);
     return false;

tests.test_body:
define nofpclass(all) float @ret_nofpclass_all_undef() {
; CHECK-LABEL: define nofpclass(all) float @ret_nofpclass_all_undef() {
; CHECK-NEXT:    ret float poison
  ret float undef
}

tests.source_program:
define nofpclass(all) float @ret_nofpclass_all_undef() {
  ret float undef
}

tests.test_body:
; Function Attrs: nocallback nofree nosync nounwind speculatable willreturn memory(none)
declare float @llvm.arithmetic.fence.f32(float) #0

define nofpclass(nan) float @undef_folds_to_poison_arg() {
; CHECK-LABEL: define nofpclass(nan) float @undef_folds_to_poison_arg() {
; CHECK-NEXT:    [[FENCE:%.*]] = call float @llvm.arithmetic.fence.f32(float nofpclass(inf zero sub norm) undef)
; CHECK-NEXT:    ret float [[FENCE]]
  %fence = call float @llvm.arithmetic.fence.f32(float nofpclass(inf zero sub norm) undef)
  ret float %fence
}

tests.source_program:
; Function Attrs: nocallback nofree nosync nounwind speculatable willreturn memory(none)
declare float @llvm.arithmetic.fence.f32(float) #0

define nofpclass(nan) float @undef_folds_to_poison_arg() {
  %fence = call float @llvm.arithmetic.fence.f32(float nofpclass(inf zero sub norm) undef)
  ret float %fence
}
